from collections import deque

class Solution:
    def timeRequiredToBuy(self, tickets, k):
        q = deque((i, t) for i, t in enumerate(tickets))
        time = 0
        while q:
            i, t = q.popleft()
            time += 1
            t -= 1
            if i == k and t == 0:
                return time
            if t > 0:
                q.append((i, t))
        return time

