class Solution:
    def timeRequiredToBuy(self, tickets, k):
        tk = tickets[k]
        total = 0
        for i, t in enumerate(tickets):
            if i <= k:
                total += min(t, tk)
            else:
                total += min(t, tk - 1)
        return total

